function createFakeClassList(initial = []) {
  const values = new Set(initial);
  return {
    toggle(name, force) {
      const shouldAdd = force === undefined ? !values.has(name) : Boolean(force);
      if (shouldAdd) values.add(name); else values.delete(name);
      return shouldAdd;
    },
    contains(name) {
      return values.has(name);
    },
    add(...names) {
      names.forEach(name => values.add(name));
    },
    remove(...names) {
      names.forEach(name => values.delete(name));
    }
  };
}

function createFakeGuideNode(dataset = {}) {
  return {
    dataset: { ...dataset },
    hidden: false,
    textContent: '',
    innerHTML: '',
    value: '',
    classList: createFakeClassList(),
    attributes: {},
    setAttribute(name, value) {
      this.attributes[name] = String(value);
    }
  };
}

function assertGuideChecklistFiltering(ctx) {
  const UI = ctx.window.UI;
  const cards = [
    createFakeGuideNode({ type: 'Bronze', risks: 'online', status: 'pending', search: 'arena online bronze' }),
    createFakeGuideNode({ type: 'Ouro', risks: 'coop collectible', status: 'completed', search: 'chapeu chapéu coop coletavel ouro' }),
    createFakeGuideNode({ type: 'Bronze', risks: 'difficulty grind', status: 'pending', search: 'hard dificuldade grind bronze' })
  ];
  const buttons = ['all', 'pending', 'completed', 'online', 'coop', 'collectible', 'difficulty', 'grind', 'missable']
    .map(filter => createFakeGuideNode({ filter }));
  const results = createFakeGuideNode();
  const empty = createFakeGuideNode();
  const search = createFakeGuideNode();

  const previousQuerySelector = ctx.document.querySelector;
  const previousQuerySelectorAll = ctx.document.querySelectorAll;
  ctx.document.querySelectorAll = selector => {
    if (selector === '.filter-btn') return buttons;
    if (selector.includes('#trophyList')) return cards;
    return [];
  };
  ctx.document.querySelector = selector => {
    if (selector === '#guideResults') return results;
    if (selector === '#guideEmptyState') return empty;
    if (selector === '#trophySearch') return search;
    return null;
  };

  try {
    UI.applyTrophyFilter('pending', '');
    assert.strictEqual(cards.filter(card => !card.classList.contains('hidden')).length, 2, 'filtro Pendentes deve mostrar apenas trofeus pendentes');
    assert(cards[1].classList.contains('hidden'), 'filtro Pendentes deve remover trofeu concluido');

    UI.applyTrophyFilter('completed', '');
    assert.strictEqual(cards.filter(card => !card.classList.contains('hidden')).length, 1, 'filtro Concluidos deve mostrar apenas concluidos');
    assert(!cards[1].classList.contains('hidden'), 'filtro Concluidos deve mostrar trofeu marcado');

    UI.applyTrophyFilter('coop', 'chapéu');
    assert.strictEqual(cards.filter(card => !card.classList.contains('hidden')).length, 1, 'busca + filtro devem funcionar juntos');
    assert(!cards[1].classList.contains('hidden'), 'busca normalizada por chapeu deve encontrar card coop/coletavel');

    UI.applyTrophyFilter('missable', '');
    assert(empty.innerHTML.includes('Limpar filtros'), 'estado vazio precisa renderizar botao Limpar filtros');
    assert(empty.innerHTML.includes('Nenhum troféu perdível encontrado'), 'estado vazio deve explicar filtro sem resultado');

    search.value = 'online';
    UI.clearGuideChecklistFilters();
    assert.strictEqual(search.value, '', 'Limpar filtros deve limpar busca');
    assert.strictEqual(cards.filter(card => !card.classList.contains('hidden')).length, 3, 'Limpar filtros deve restaurar lista');
  } finally {
    ctx.document.querySelector = previousQuerySelector;
    ctx.document.querySelectorAll = previousQuerySelectorAll;
  }
}

