function assertGuidePresenter() {
  const ctx = loadBrowserScripts([
    'src/shared/editorialModel.js',
    'src/shared/cardModel.js',
    'public/js/guide-presenter.js'
  ]);
  const presenter = ctx.window.GuidePresenter;
  assert(presenter, 'GuidePresenter indisponível');

  const currentGame = { name: 'Game A', slug: 'game-a', difficulty: 3, time: '8-10 horas', trophy_count: 25 };
  const availableGames = [
    currentGame,
    { name: 'Game B', slug: 'game-b', difficulty: 3, time: '10 horas', trophy_count: 27, roadmap_count: 2 },
    { name: 'Game C', slug: 'game-c', difficulty: 8, time: '70 horas', trophy_count: 60 }
  ];
  const library = {
    'game-a': { slug: 'game-a', completed: ['t1', 't2'] }
  };

  const model = presenter.buildGuideRenderModel(currentGame, library, availableGames, {
    getSlug: game => game.slug,
    normalizeLibraryEntry: game => ({ ...game, completed: [] }),
    limit: 2
  });

  assert.strictEqual(model.isSaved, true);
  assert.strictEqual(Array.from(model.completedTrophies).join(','), 't1,t2');
  assert.strictEqual(model.relatedGames[0].game.slug, 'game-b');
  assert(model.comparisonModel, 'comparisonModel indisponível');
  assert.strictEqual(model.comparisonModel.lead.slug, 'game-b');
  assert(model.comparisonModel.rows.length >= 1, 'comparisonModel precisa ter linhas');
  const fallbackCtx = loadBrowserScript('public/js/guide-presenter.js');
  const fallbackRelated = fallbackCtx.window.GuidePresenter.buildRelatedGames(
    { slug: 'base', difficulty: 5, time: '', trophy_count: 20 },
    [{ slug: 'related', name: 'Relacionado', difficulty: 4, time: '', trophy_count: 20 }],
    { getSlug: game => game.slug, limit: 1 }
  );
  assert.strictEqual(fallbackRelated[0]?.badge, 'Ritmo parecido', 'fallback do GuidePresenter nao deve comparar tempos ausentes');
}


