    dlc: 'Lista base',
    ideal_for: 'Bom para quem quer uma platina direta e organizada.',
    avoid_for: 'Evite se você busca um desafio muito alto.',
    best_for_when: 'Comece quando quiser algo direto.',
    roadmap: ['Começar', 'Avançar', 'Limpar', 'Finalizar'],
