function assertLote4NarrativeGuideRoadmaps() {
  const sampleGames = require(path.join(ROOT, 'src/data/sampleGames'));
  const guideModel = require(path.join(ROOT, 'src/shared/guideViewModel'));
  const bySlug = new Map(sampleGames.map(game => [game.slug, game]));
  const expectedCounts = {
    'detroit-become-human': { total: 49, Platina: 1, Ouro: 3, Prata: 5, Bronze: 40 },
    'heavy-rain': { total: 57, Platina: 1, Ouro: 2, Prata: 4, Bronze: 50 },
    'beyond-two-souls': { total: 46, Platina: 1, Ouro: 3, Prata: 6, Bronze: 36 },
    'the-quarry': { total: 41, Platina: 1, Ouro: 4, Prata: 7, Bronze: 29 },
    'until-dawn': { total: 19, Platina: 1, Ouro: 9, Prata: 5, Bronze: 4 },
    'life-is-strange-true-colors': { total: 41, Platina: 1, Ouro: 6, Prata: 0, Bronze: 34 },
    'life-is-strange-double-exposure': { total: 33, Platina: 1, Ouro: 3, Prata: 21, Bronze: 8 },
    'life-is-strange-remastered': { total: 61, Platina: 1, Ouro: 1, Prata: 0, Bronze: 59 },
    'road-96': { total: 12, Platina: 1, Ouro: 11, Prata: 0, Bronze: 0 },
    'what-remains-of-edith-finch': { total: 12, Platina: 1, Ouro: 11, Prata: 0, Bronze: 0 },
    stray: { total: 25, Platina: 1, Ouro: 7, Prata: 9, Bronze: 8 },
    'little-nightmares-ii': { total: 35, Platina: 1, Ouro: 3, Prata: 15, Bronze: 16 },
    'a-way-out': { total: 15, Platina: 1, Ouro: 10, Prata: 4, Bronze: 0 },
    'it-takes-two': { total: 21, Platina: 1, Ouro: 10, Prata: 0, Bronze: 10 },
    'split-fiction': { total: 21, Platina: 1, Ouro: 8, Prata: 5, Bronze: 7 },
    reanimal: { total: 32, Platina: 1, Ouro: 4, Prata: 16, Bronze: 11 }
  };
  const requiredFields = [
    'runs_summary',
    'online_summary',
    'grind_summary',
    'dlc_scope',
    'difficulty_reason',
    'time_reason',
    'first_run_advice',
    'cleanup_advice',
    'before_you_start',
    'best_for',
    'avoid_if'
  ];
  const countTypes = game => game.trophies.reduce((counts, trophy) => {
    counts[trophy.type] = (counts[trophy.type] || 0) + 1;
    return counts;
  }, { Platina: 0, Ouro: 0, Prata: 0, Bronze: 0 });
  const editorialBody = game => normalizeEditorialSmokeText([
    ...requiredFields.map(field => game[field]),
    game.missable,
    game.missable_summary,
    ...(game.roadmap || []),
    ...game.trophies.map(trophy => `${trophy.name} ${trophy.description} ${trophy.tip}`)
  ].join(' '));
  const summaryCardValue = (game, label) => guideModel
    .buildGuideSummaryCards(game, guideModel.buildGuideViewModel(game, []))
    .find(card => card.label === label)?.value || '';
  const summaryOnlineValue = game => normalizeEditorialSmokeText(summaryCardValue(game, 'Online'));
  const summaryCoopValue = game => normalizeEditorialSmokeText(summaryCardValue(game, 'Coop'));

  Object.entries(expectedCounts).forEach(([slug, expected]) => {
    const game = bySlug.get(slug);
    assert(game, `${slug} deve existir no Lote 4`);
    assert(Array.isArray(game.roadmap) && game.roadmap.length >= 5, `${slug} deve ter roadmap narrativo especifico`);
    requiredFields.forEach(field => {
      assert(game[field] && String(game[field]).length > 20, `${slug} deve preencher ${field} com orientacao especifica`);
    });
    assert.strictEqual(game.is_verified, false, `${slug} nao deve ser marcado como verificado manualmente`);
    assert.strictEqual(game.verification_status, 'review', `${slug} deve permanecer em revisao editorial`);
    assert.strictEqual(game.trophies.length, expected.total, `${slug} nao deve alterar contagem de trofeus`);
    assert.deepStrictEqual(countTypes(game), {
      Platina: expected.Platina,
      Ouro: expected.Ouro,
      Prata: expected.Prata,
      Bronze: expected.Bronze
    }, `${slug} nao deve alterar distribuicao de tipos`);
    const body = editorialBody(game);
    assert(/chapter select|selecao de capitulos|collectible mode|new game\+|nova campanha|segunda rota|seleção de capitulos|replay|save manual|coop|autosave/.test(body), `${slug} deve explicar cleanup, replay, saves ou coop quando aplicavel`);
    assert(/colet|finais|escolh|chapter select|collectible mode|rota|capitulo|campanha|speedrun|side stories|benches|caixoes|estatuas|trofeus opcionais/.test(body), `${slug} deve destacar escolhas, finais, coletaveis ou trofeus opcionais`);
  });

  assert(!bySlug.has('alone-in-the-dark'), 'Alone in the Dark nao deve ser criado pelo Lote 4');
  assert(!bySlug.has('firewatch'), 'Firewatch nao deve ser criado pelo Lote 4');
  assert(!bySlug.has('tell-me-why'), 'Tell Me Why nao deve ser criado pelo Lote 4');

  const assertBody = (slug, pattern, message) => {
    assert(pattern.test(editorialBody(bySlug.get(slug))), message);
  };

  assertBody('detroit-become-human', /chapter select.*continue jogando|chapter select.*consequencia.*persistir/, 'Detroit deve explicar Chapter Select com persistencia de consequencias');
  assertBody('detroit-become-human', /todos vivos|todos mortos|i'll be back|i’ll be back|revistas|hank|multiplos finais/, 'Detroit deve destacar vivos/mortos, Connor, revistas, Hank e finais');
  assertBody('heavy-rain', /perfect crime.*all endings|all endings.*perfect crime/, 'Heavy Rain deve mencionar Perfect Crime e All Endings');
  assertBody('heavy-rain', /chapter select.*save|continue jogando com save|continuar a linha do tempo/, 'Heavy Rain deve orientar Chapter Select com save e consequencias');
  assertBody('beyond-two-souls', /all endings|saved all|a better world|uncontrollable|explorer/, 'Beyond deve destacar All Endings, Saved All, A Better World, Uncontrollable e Explorer');
  assertBody('beyond-two-souls', /duo mode|segundo controle|app compativel|coop local/, 'Beyond deve tratar Duo Mode/local corretamente');
  assert.strictEqual(summaryOnlineValue(bySlug.get('beyond-two-souls')).includes('online/multiplayer'), false, 'Beyond nao deve aparecer como online/multiplayer obrigatorio');
  assertBody('the-quarry', /chapter select.*continuar|continuar a partir do capitulo|continue jogando/, 'The Quarry deve explicar limite de Chapter Select');
  assertBody('the-quarry', /todos vivos|todos mortos|infectados|evidencias|pistas|taros/, 'The Quarry deve destacar vivos/mortos/infectados e coletaveis');
  assert(/sem coop obrigatorio/.test(summaryCoopValue(bySlug.get('the-quarry'))), 'The Quarry nao deve aparecer como coop obrigatorio');
  assertBody('until-dawn', /todos vivos|ninguem vivo|totems|clues|interactables/, 'Until Dawn deve mencionar vivos/mortos e coletaveis');
  assertBody('until-dawn', /ps4|ps5|pc/, 'Until Dawn deve avisar diferenca de versao quando aplicavel');
  assertBody('life-is-strange-true-colors', /wavelengths.*fora|wavelengths.*separad|collectible mode|memorias|memories/, 'True Colors deve separar Wavelengths e explicar memórias/Collectible Mode');
  assert(/sem coop obrigatorio/.test(summaryCoopValue(bySlug.get('life-is-strange-double-exposure'))), 'Double Exposure nao deve aparecer como coop');
  assertBody('life-is-strange-double-exposure', /exclusive cat content|bay\/bae|segunda rota|polaroids|fotos/, 'Double Exposure deve separar DLC do gato e destacar rotas/coletaveis');
  assertBody('life-is-strange-remastered', /before the storm remastered|collectible mode|50 fotos opcionais|chapter select/, 'Life is Strange Remastered nao deve misturar Before the Storm e deve explicar fotos por capitulo');
  assertBody('road-96', /mile 0|18 fitas|zoe|telefone publico|gato|cairn|new game\+|nova campanha/, 'Road 96 deve separar Mile 0 e destacar fitas/eventos/nova campanha');
  assertBody('what-remains-of-edith-finch', /versao ps5|ps4 nao possui platina|replay de historias|all roads/, 'Edith Finch deve indicar versao PS5, PS4 sem platina e replay de historias');
  assertBody('stray', /i am speed|27 b-12 memories|6 badges|12 scratch points|8 sheet music|4 energy drinks|chapter select/, 'Stray deve destacar I am Speed, Chapter Select e quantidades de coletaveis');
  assertBody('little-nightmares-ii', /glitching remains|chapeus|chapter select|selecao de capitulos/, 'Little Nightmares II deve mencionar Glitching Remains, chapeus e Chapter Select');
  assert(/2 jogadores obrigatorios|coop obrigat/.test(summaryCoopValue(bySlug.get('a-way-out'))), 'A Way Out deve aparecer com coop obrigatorio');
  assert(/2 jogadores obrigatorios|coop obrigat/.test(summaryCoopValue(bySlug.get('it-takes-two'))), 'It Takes Two deve aparecer com coop obrigatorio');
  assert(/2 jogadores obrigatorios|coop obrigat/.test(summaryCoopValue(bySlug.get('split-fiction'))), 'Split Fiction deve aparecer com coop obrigatorio');
  assertBody('a-way-out', /coop local ou online|local ou online|selecao de capitulos|nao pode ser platinado solo/, 'A Way Out deve explicar coop obrigatorio local/online e cleanup por capitulos');
  assertBody('it-takes-two', /nao pode ser platinado solo|25 minigames|chapter select|friend's pass|friends pass/, 'It Takes Two deve explicar coop obrigatorio, minigames, Chapter Select e Friend Pass');
  assertBody('split-fiction', /nao ha rota solo|12 side stories|6 benches|friend pass|autosave|chapter select/, 'Split Fiction deve explicar coop obrigatorio, Side Stories, benches, Friend Pass e autosave');
  assert(/sem coop obrigatorio/.test(summaryCoopValue(bySlug.get('reanimal'))), 'REANIMAL nao deve aparecer como coop obrigatorio');
  assertBody('reanimal', /solo|coop opcional|caixoes|estatuas|mascaras|posteres|final secreto|precisa validar|revisao/, 'REANIMAL deve comunicar solo/coop opcional, coletaveis criticos e revisao');
  assert(!/coop obrigatorio|exige 2 jogadores/.test(editorialBody(bySlug.get('reanimal'))), 'REANIMAL nao deve afirmar coop obrigatorio');
}

function assertFinalQaPriorityBlockerFixes() {
  const sampleGames = require(path.join(ROOT, 'src/data/sampleGames'));
  const guideModel = require(path.join(ROOT, 'src/shared/guideViewModel'));
  const bySlug = new Map(sampleGames.map(game => [game.slug, game]));
  const allowedCounts = {
    'beyond-two-souls': { total: 46, Platina: 1, Ouro: 3, Prata: 6, Bronze: 36 },
    'road-96': { total: 12, Platina: 1, Ouro: 11, Prata: 0, Bronze: 0 },
    'baldurs-gate-3': { total: 54, Platina: 1, Ouro: 2, Prata: 4, Bronze: 47 },
    'detroit-become-human': { total: 49, Platina: 1, Ouro: 3, Prata: 5, Bronze: 40 },
    'heavy-rain': { total: 57, Platina: 1, Ouro: 2, Prata: 4, Bronze: 50 },
    'until-dawn': { total: 19, Platina: 1, Ouro: 9, Prata: 5, Bronze: 4 },
    'life-is-strange-true-colors': { total: 41, Platina: 1, Ouro: 6, Prata: 0, Bronze: 34 }
  };
  const countTypes = game => game.trophies.reduce((counts, trophy) => {
    counts[trophy.type] = (counts[trophy.type] || 0) + 1;
    return counts;
  }, { Platina: 0, Ouro: 0, Prata: 0, Bronze: 0 });
  const summaryCardValue = (game, label) => guideModel
    .buildGuideSummaryCards(game, guideModel.buildGuideViewModel(game, []))
    .find(card => card.label === label)?.value || '';
  const normalizedBody = game => normalizeEditorialSmokeText([
    game.missable,
    game.missable_summary,
    game.online_summary,
    game.dlc_scope,
    game.before_you_start,
    game.cleanup_advice,
    ...(game.roadmap || []),
    ...game.trophies.map(trophy => `${trophy.name} ${trophy.description} ${trophy.tip}`)
  ].join(' '));

  Object.entries(allowedCounts).forEach(([slug, expected]) => {
    const game = bySlug.get(slug);
    assert(game, `${slug} deve existir para QA final`);
    assert.strictEqual(game.is_verified, false, `${slug} nao deve virar verificado`);
    assert.strictEqual(game.verification_status, 'review', `${slug} deve permanecer em revisao`);
    assert.strictEqual(game.trophies.length, expected.total, `${slug} nao deve alterar contagem`);
    assert.deepStrictEqual(countTypes(game), {
      Platina: expected.Platina,
      Ouro: expected.Ouro,
      Prata: expected.Prata,
      Bronze: expected.Bronze
    }, `${slug} nao deve alterar tipos`);
  });

  const beyond = bySlug.get('beyond-two-souls');
  assert.strictEqual(summaryCardValue(beyond, 'Online'), 'Sem online obrigatório', 'Beyond nao deve aparecer como online obrigatorio');
  assert.strictEqual(summaryCardValue(beyond, 'Coop'), 'Sem coop obrigatório', 'Beyond nao deve aparecer como 2 jogadores obrigatorios');
  assert(/duo mode\/local/.test(normalizedBody(beyond)) && /nao.*coop online obrigatorio/.test(normalizedBody(beyond)), 'Beyond deve manter Duo Mode/local claro sem coop online obrigatorio');
  assert.strictEqual(beyond.trophies.filter(trophy => guideModel.getGuideTrophyTags(trophy, beyond).some(tag => tag.id === 'coop')).length, 0, 'Beyond nao deve gerar tag coop por Duo Mode/local');

  const road96 = bySlug.get('road-96');
  assert.strictEqual(summaryCardValue(road96, 'DLC'), 'Conteúdo extra fora', 'Road 96 nao deve mostrar DLC no escopo');
  assert(/mile 0.*fora do escopo|fora do escopo.*mile 0/.test(normalizedBody(road96)), 'Road 96 deve manter Mile 0 fora do escopo');

  const baldursGate3 = bySlug.get('baldurs-gate-3');
  assert.strictEqual(summaryCardValue(baldursGate3, 'DLC'), 'Conteúdo extra fora', 'Baldur\'s Gate 3 nao deve mostrar DLC no escopo de forma ambigua');
  assert(/lista atual cadastrada/.test(normalizedBody(baldursGate3)) && /validar separadamente/.test(normalizedBody(baldursGate3)), 'Baldur\'s Gate 3 deve explicar escopo da lista atual e validacao separada');

  const detroit = bySlug.get('detroit-become-human');
  assert(/atencao.*rota\/capitulo/.test(normalizedBody(detroit)) && /poucos.*perdiveis definitivos/.test(normalizedBody(detroit)), 'Detroit deve diferenciar atencao por rota de perdivel definitivo');
  assert(/chapter select.*consequencias.*persistem|consequencias.*persistem.*chapter select/.test(normalizedBody(detroit)), 'Detroit deve explicar persistencia do Chapter Select');
  assert(detroit.trophies.filter(trophy => trophy.is_missable).length >= 40, 'Detroit deve manter alertas de missable sem apagar riscos');

  const heavyRain = bySlug.get('heavy-rain');
  assert(/atencao.*capitulo\/rota/.test(normalizedBody(heavyRain)) && /recuperavel por chapter select/.test(normalizedBody(heavyRain)), 'Heavy Rain deve diferenciar rota/final de trofeu recuperavel por Chapter Select');
  assert(/perfect crime/.test(normalizedBody(heavyRain)) && /all endings/.test(normalizedBody(heavyRain)), 'Heavy Rain deve manter Perfect Crime e All Endings claros');
  assert(heavyRain.trophies.filter(trophy => trophy.is_missable).length >= 50, 'Heavy Rain deve manter alertas de missable sem apagar riscos');

  const untilDawn = bySlug.get('until-dawn');
  assert(/atencao.*rota\/capitulo/.test(normalizedBody(untilDawn)) && /coletaveis por capitulo/.test(normalizedBody(untilDawn)), 'Until Dawn deve diferenciar rotas de morte e coletaveis por capitulo');
  assert(/todos vivos|ninguem vivo|totems|clues|interactables/.test(normalizedBody(untilDawn)), 'Until Dawn deve manter vivos/mortos e coletaveis claros');
  assert(untilDawn.trophies.filter(trophy => trophy.is_missable).length >= 18, 'Until Dawn deve manter alertas de missable sem apagar riscos');

  const trueColors = bySlug.get('life-is-strange-true-colors');
  assert.strictEqual(summaryCardValue(trueColors, 'Online'), 'Sem online obrigatório', 'True Colors nao deve aparecer como online obrigatorio tradicional');
  assert.strictEqual(summaryCardValue(trueColors, 'Coop'), 'Sem coop obrigatório', 'True Colors nao deve aparecer como multiplayer/coop');
  assert(/atencao tecnica\/psn/.test(normalizedBody(trueColors)) && /nao.*multiplayer/.test(normalizedBody(trueColors)), 'True Colors deve tratar PSN como atencao tecnica, nao multiplayer');
  assert.strictEqual(trueColors.trophies.filter(trophy => guideModel.getGuideTrophyTags(trophy, trueColors).some(tag => tag.id === 'online')).length, 0, 'True Colors nao deve gerar tag online por atencao tecnica/PSN');
}

function assertPriorityGuideEditorialTrust() {
  const sampleGames = require(path.join(ROOT, 'src/data/sampleGames'));
  const guideModel = require(path.join(ROOT, 'src/shared/guideViewModel'));
  const expectedCounts = {
    'hollow-knight': { total: 35, Platina: 1, Ouro: 5, Prata: 11, Bronze: 18 },
    'it-takes-two': { total: 21, Platina: 1, Ouro: 10, Prata: 0, Bronze: 10 },
    'a-way-out': { total: 15, Platina: 1, Ouro: 10, Prata: 4, Bronze: 0 },
    'little-nightmares-ii': { total: 35, Platina: 1, Ouro: 3, Prata: 15, Bronze: 16 },
    'dead-cells': { total: 54, Platina: 1, Ouro: 1, Prata: 11, Bronze: 41 },
    'monster-hunter-world': { total: 50, Platina: 1, Ouro: 2, Prata: 11, Bronze: 36 },
    'clair-obscur-expedition-33': { total: 56, Platina: 1, Ouro: 2, Prata: 5, Bronze: 48 }
  };
  const bySlug = new Map(sampleGames.map(game => [game.slug, game]));
  const countTag = (game, tagId) => game.trophies.filter(trophy => guideModel.getGuideTrophyTags(trophy).some(tag => tag.id === tagId)).length;
  const countChecklistTag = (game, tagId) => game.trophies.filter(trophy => guideModel.getGuideTrophyTags(trophy, game).some(tag => tag.id === tagId)).length;
  const searchMatches = (game, term, tagId = '') => {
    const normalizedTerm = guideModel.normalizeGuideSignalText(term);
    return game.trophies.filter(trophy => {
      const tags = guideModel.getGuideTrophyTags(trophy, game);
      const text = guideModel.getGuideTrophySearchText(trophy, tags);
      const tagOk = !tagId || tags.some(tag => tag.id === tagId);
      return tagOk && text.includes(normalizedTerm);
    });
  };
  const countTypes = game => game.trophies.reduce((counts, trophy) => {
    counts[trophy.type] = (counts[trophy.type] || 0) + 1;
    return counts;
  }, { Platina: 0, Ouro: 0, Prata: 0, Bronze: 0 });
  const editorialBody = game => normalizeEditorialSmokeText([
    game.overview,
    game.runs_summary,
    game.online_summary,
    game.grind_summary,
    game.missable_summary,
    game.difficulty_reason,
    game.time_reason,
    game.first_run_advice,
    game.cleanup_advice,
    game.before_you_start,
    game.best_for,
    game.avoid_if,
    ...(game.roadmap || []),
    ...game.trophies.map(trophy => `${trophy.name} ${trophy.description} ${trophy.tip}`)
  ].join(' '));
  const roadmapTitles = game => normalizeEditorialSmokeText(
    guideModel.buildGuideViewModel(game, []).roadmapStages.map(stage => stage.title).join(' ')
  );
  const summaryCardValue = (game, label) => guideModel
    .buildGuideSummaryCards(game, guideModel.buildGuideViewModel(game, []))
    .find(card => card.label === label)?.value || '';
  const summaryLabels = game => guideModel
    .buildGuideSummaryCards(game, guideModel.buildGuideViewModel(game, []))
    .map(card => card.label);
  const summaryOnlineValue = game => summaryCardValue(game, 'Online');
  const summaryCoopValue = game => summaryCardValue(game, 'Coop');

  Object.entries(expectedCounts).forEach(([slug, expected]) => {
    const game = bySlug.get(slug);
    assert(game, `${slug} deve existir em sampleGames`);
    assert.strictEqual(game.trophies.length, expected.total, `${slug} deve manter total de trofeus`);
    assert(game.trophies.every(trophy => trophy.name_pt && trophy.name_pt.trim()), `${slug} deve ter name_pt em todos os trofeus do piloto`);
    assert.strictEqual(new Set(game.trophies.map(trophy => trophy.id)).size, game.trophies.length, `${slug} nao pode duplicar trophy_code ao adicionar name_pt`);
    assert.deepStrictEqual(countTypes(game), {
      Platina: expected.Platina,
      Ouro: expected.Ouro,
      Prata: expected.Prata,
      Bronze: expected.Bronze
    }, `${slug} deve manter distribuicao por tipo`);
    assert.strictEqual(game.slug, slug, `${slug} deve manter slug funcional`);
    const labels = summaryLabels(game);
    ['Tempo estimado', 'Dificuldade', 'Troféus', 'Jogadas/runs', 'Perdíveis', 'Online', 'Coop', 'DLC', 'Chapter Select', 'Platina/100%'].forEach(label => {
      assert(labels.includes(label), `${slug} deve expor ${label} no resumo rapido da platina`);
    });
    assert(guideModel.buildGuideViewModel(game, []).beforeStartItems.length <= 5, `${slug} deve mostrar no maximo 5 alertas antes de comecar`);
  });

  const translatedOutsidePilot = sampleGames
    .filter(game => !Object.keys(expectedCounts).includes(game.slug))
    .flatMap(game => game.trophies.filter(trophy => trophy.name_pt));
  assert.strictEqual(translatedOutsidePilot.length, 0, 'somente os guias piloto devem receber name_pt nesta fase');

  ['hollow-knight', 'it-takes-two', 'a-way-out', 'little-nightmares-ii'].forEach(slug => {
    const generatedRoadmap = roadmapTitles(bySlug.get(slug));
    assert(!/guild cards?|high rank|coroas?|crowns?|iceborne|sos/.test(generatedRoadmap), `${slug} nao deve gerar titulo de roadmap de Monster Hunter`);
  });

  const hollowKnight = bySlug.get('hollow-knight');
  assert.strictEqual(countTag(hollowKnight, 'online'), 0, 'Hollow Knight nao deve ter tag online derivada');
  assert.strictEqual(countTag(hollowKnight, 'coop'), 0, 'Hollow Knight nao deve ter tag coop derivada');
  assert.strictEqual(countChecklistTag(hollowKnight, 'online'), 0, 'checklist de Hollow Knight nao deve ter filtro Online preenchido indevidamente');
  assert.strictEqual(countChecklistTag(hollowKnight, 'coop'), 0, 'checklist de Hollow Knight nao deve ter filtro Coop preenchido indevidamente');
  assert(hollowKnight.trophies.some(trophy => trophy.name === 'The Hollow Knight' && trophy.name_pt === 'O Cavaleiro Vazio'), 'Hollow Knight deve preservar nome oficial e exibir traducao editorial');
  assert(searchMatches(hollowKnight, 'cavaleiro').some(trophy => trophy.name === 'The Hollow Knight'), 'busca por nome em portugues deve encontrar The Hollow Knight');
  assert(searchMatches(hollowKnight, 'hollow').some(trophy => trophy.name === 'The Hollow Knight'), 'busca por nome oficial em ingles deve continuar encontrando The Hollow Knight');
  assert(/sem online obrigatorio|sem online/.test(normalizeEditorialSmokeText(summaryOnlineValue(hollowKnight))), 'Hollow Knight deve aparecer sem online no resumo editorial');
  assert(/void heart/.test(roadmapTitles(hollowKnight)), 'Hollow Knight deve destacar Void Heart no roadmap derivado');
  assert(/void heart|the hollow knight/.test(normalizeEditorialSmokeText(guideModel.buildGuideViewModel(hollowKnight, []).beforeStartItems.map(item => `${item.title} ${item.detail}`).join(' '))), 'Hollow Knight deve alertar Void Heart/final base antes do checklist');

  const itTakesTwo = bySlug.get('it-takes-two');
  assert.strictEqual(countTag(itTakesTwo, 'online'), 0, 'It Takes Two nao deve virar online tradicional');
  assert(countChecklistTag(itTakesTwo, 'coop') > 0, 'checklist de It Takes Two deve permitir filtro Coop por coop obrigatorio');
  assert(searchMatches(itTakesTwo, 'coop', 'coop').length > 0, 'busca por coop em It Takes Two deve encontrar trofeus coop');
  assert(searchMatches(itTakesTwo, 'megalomania de minigames').some(trophy => trophy.name === 'Minigame Megalomania'), 'busca deve encontrar It Takes Two por name_pt');
  assert(/2 jogadores obrigatorios|coop obrigat/.test(normalizeEditorialSmokeText(summaryCoopValue(itTakesTwo))), 'It Takes Two deve aparecer como coop obrigatorio');
  assert(/2 jogadores obrigatorios|coop/.test(normalizeEditorialSmokeText(guideModel.buildGuideViewModel(itTakesTwo, []).beforeStartItems.map(item => `${item.title} ${item.detail}`).join(' '))), 'It Takes Two deve alertar coop obrigatorio antes do checklist');
  assert(/2 jogadores|coop local|coop online/.test(normalizeEditorialSmokeText(itTakesTwo.online_summary)), 'It Takes Two deve explicar coop local ou online');
  assert(/25 minigames/.test(roadmapTitles(itTakesTwo)), 'It Takes Two deve manter etapa dos 25 minigames');

  const aWayOut = bySlug.get('a-way-out');
  assert.strictEqual(countTag(aWayOut, 'online'), 0, 'A Way Out nao deve virar online exclusivo');
  assert(countChecklistTag(aWayOut, 'coop') > 0, 'checklist de A Way Out deve permitir filtro Coop por coop obrigatorio');
  assert(searchMatches(aWayOut, 'coop', 'coop').length > 0, 'busca por coop em A Way Out deve encontrar trofeus coop');
  assert(searchMatches(aWayOut, 'todas as saidas').some(trophy => trophy.name === 'All The Ways Out'), 'busca deve encontrar A Way Out por name_pt sem acento');
  assert(/2 jogadores obrigatorios|coop obrigat/.test(normalizeEditorialSmokeText(summaryCoopValue(aWayOut))), 'A Way Out deve aparecer como coop obrigatorio');
  assert(/2 jogadores obrigatorios|coop/.test(normalizeEditorialSmokeText(guideModel.buildGuideViewModel(aWayOut, []).beforeStartItems.map(item => `${item.title} ${item.detail}`).join(' '))), 'A Way Out deve alertar coop obrigatorio antes do checklist');
  assert(/2 jogadores|coop local|coop online/.test(normalizeEditorialSmokeText(aWayOut.online_summary)), 'A Way Out deve explicar coop local ou online');
  assert(/eventos opcionais|all the ways out/.test(`${roadmapTitles(aWayOut)} ${editorialBody(aWayOut)}`), 'A Way Out deve manter foco em eventos opcionais por capitulo');

  const littleNightmaresII = bySlug.get('little-nightmares-ii');
  assert(countChecklistTag(littleNightmaresII, 'collectible') > 0, 'Little Nightmares II deve ter filtro Coletaveis no checklist');
  assert(searchMatches(littleNightmaresII, 'chapéu', 'collectible').length > 0 || searchMatches(littleNightmaresII, 'chapeu', 'collectible').length > 0, 'busca por chapeu deve encontrar coletaveis de Little Nightmares II');
  assert(searchMatches(littleNightmaresII, 'pipoca').some(trophy => trophy.name === 'Popcorn'), 'busca deve encontrar Popcorn por name_pt Pipoca');
  assert(/sem online obrigatorio|sem online/.test(normalizeEditorialSmokeText(summaryOnlineValue(littleNightmaresII))), 'Little Nightmares II deve aparecer sem online');
  assert(/chapter select|selecao de capitulos/.test(editorialBody(littleNightmaresII)), 'Little Nightmares II deve orientar cleanup por Chapter Select');
  assert(/chapter select|colet|chapeu|chapéu/.test(normalizeEditorialSmokeText(guideModel.buildGuideViewModel(littleNightmaresII, []).beforeStartItems.map(item => `${item.title} ${item.detail}`).join(' '))), 'Little Nightmares II deve destacar coletaveis/chapter select antes do checklist');
  assert(!/coop|co-op|multiplayer|high rank|guild cards?|iceborne|coroas?/.test(roadmapTitles(littleNightmaresII)), 'Little Nightmares II nao deve misturar coop ou Monster Hunter no roadmap');
  assert(!/preorder|bonus/.test(editorialBody(littleNightmaresII)), 'Little Nightmares II nao deve tratar preorder/bonus como trofeu ou roadmap');

  const deadCells = bySlug.get('dead-cells');
  assert(countChecklistTag(deadCells, 'grind') > 0, 'Dead Cells deve ter filtro Grind no checklist');
  assert(countChecklistTag(deadCells, 'difficulty') > 0, 'Dead Cells deve ter filtro Dificuldade no checklist');
  assert(searchMatches(deadCells, 'precisa de uma mao').some(trophy => trophy.name === 'Do You Need... A Hand?? Bahaha!'), 'busca deve encontrar Dead Cells por name_pt sem acento');
  const deadCellsProgress = guideModel.buildGuideViewModel(deadCells, [deadCells.trophies[0].id]);
  assert.strictEqual(deadCellsProgress.completed, 1, 'marcar trofeu deve atualizar progresso do view model');
  assert.strictEqual(deadCellsProgress.pending, deadCells.trophies.length - 1, 'marcar trofeu deve atualizar pendentes do view model');
  assert(/sem online obrigatorio|sem online/.test(normalizeEditorialSmokeText(summaryOnlineValue(deadCells))), 'Dead Cells deve aparecer sem online');
  assert(/54 trofeus|jogo base/.test(normalizeEditorialSmokeText(deadCells.dlc_scope)), 'Dead Cells deve declarar base game com 54 trofeus');
  assert(/base game|boss stem|sem dano|dlc/.test(normalizeEditorialSmokeText(guideModel.buildGuideViewModel(deadCells, []).beforeStartItems.map(item => `${item.title} ${item.detail}`).join(' '))), 'Dead Cells deve destacar base game, Boss Stem Cells ou chefes sem dano antes do checklist');
  assert(!/castlevania|bad seed|fatal falls|queen and the sea|the bank|derelict distillery|rise of the giant/.test(editorialBody(deadCells)), 'Dead Cells nao deve misturar DLCs no roadmap ou checklist');

  const monsterHunterWorld = bySlug.get('monster-hunter-world');
  assert(/online\/multiplayer/.test(summaryOnlineValue(monsterHunterWorld)), 'Monster Hunter: World deve aparecer como online/multiplayer');
  assert(countChecklistTag(monsterHunterWorld, 'online') > 0, 'Monster Hunter: World deve manter tags online');
  assert(searchMatches(monsterHunterWorld, 'online', 'online').length > 0, 'busca por online em Monster Hunter: World deve encontrar trofeus online');
  assert(searchMatches(monsterHunterWorld, 'coroa').length > 0, 'busca por coroa em Monster Hunter: World deve encontrar trofeus de coroas');
  assert(searchMatches(monsterHunterWorld, 'mestre das coroas gigantes').some(trophy => trophy.name === 'Giant Crown Master'), 'busca deve encontrar Monster Hunter por name_pt de coroa gigante');
  assert(/iceborne/.test(normalizeEditorialSmokeText(monsterHunterWorld.dlc_scope)) && /platina propria/.test(normalizeEditorialSmokeText(monsterHunterWorld.dlc_scope)), 'Monster Hunter: World deve separar Iceborne como lista propria');
  assert(/iceborne|coroa|guild card|sos|online/.test(normalizeEditorialSmokeText(guideModel.buildGuideViewModel(monsterHunterWorld, []).beforeStartItems.map(item => `${item.title} ${item.detail}`).join(' '))), 'Monster Hunter: World deve destacar online/Iceborne/coroas antes do checklist');
  assert(!/iceborne|master rank/.test(normalizeEditorialSmokeText(monsterHunterWorld.trophies.map(trophy => `${trophy.name} ${trophy.description} ${trophy.tip}`).join(' '))), 'Monster Hunter: World nao deve misturar trofeus de Iceborne');
  assert(/guild cards?|sos|coroas?/.test(editorialBody(monsterHunterWorld)), 'Monster Hunter: World deve manter alertas de SOS, Guild Cards e coroas');

  const clairObscur = bySlug.get('clair-obscur-expedition-33');
  assert(searchMatches(clairObscur, 'maior expedicao da historia').some(trophy => trophy.name === 'The Greatest Expedition in History'), 'busca deve encontrar Clair Obscur por name_pt sem acento');
  assert(/sem online obrigatorio|sem online/.test(normalizeEditorialSmokeText(summaryOnlineValue(clairObscur))), 'Clair Obscur deve aparecer sem online');
  assert(/old key|mime|maelle|discos|new game\+/.test(editorialBody(clairObscur)), 'Clair Obscur deve manter alertas de prologo, Old Key, Mime, Maelle, discos e New Game+');
  assert(/old key|mime|maelle|new game\+|discos/.test(normalizeEditorialSmokeText(guideModel.buildGuideViewModel(clairObscur, []).beforeStartItems.map(item => `${item.title} ${item.detail}`).join(' '))), 'Clair Obscur deve destacar prologo/perdiveis antes do checklist');
  assert.strictEqual(countTag(clairObscur, 'online'), 0, 'Clair Obscur nao deve ter tag online derivada');
}

function assertFileContains(relPath, needle) {
  const content = read(relPath);
  assert(content.includes(needle), `${relPath} precisa conter ${needle}`);
}

function writeFixtureFile(filePath, content = '') {
  fs.mkdirSync(path.dirname(filePath), { recursive: true });
  fs.writeFileSync(filePath, content);
}

function assertReleaseCheckModule() {
  const releaseCheck = require(path.join(ROOT, 'scripts/check-release.js'));
  const tempRoot = fs.mkdtempSync(path.join(os.tmpdir(), 'atlas-release-check-'));

  try {
    writeFixtureFile(path.join(tempRoot, 'package.json'), '{"name":"fixture"}\n');
    writeFixtureFile(path.join(tempRoot, 'package-lock.json'), '{"lockfileVersion":3}\n');
    writeFixtureFile(path.join(tempRoot, '.env.example'), 'SESSION_SECRET=exemplo-local\n');
    writeFixtureFile(path.join(tempRoot, 'README.md'), '# Fixture\n');
    assert.deepStrictEqual(releaseCheck.scanReleaseTree(tempRoot), [], 'pacote limpo com .env.example deve passar no release check');

    writeFixtureFile(path.join(tempRoot, 'database.sqlite'), '');
    let blocked = releaseCheck.scanReleaseTree(tempRoot);
    assert(blocked.some(item => item.packagePath === 'database.sqlite' && /SQLite local/.test(item.reason)), 'database.sqlite falso deve bloquear release');
    fs.rmSync(path.join(tempRoot, 'database.sqlite'), { force: true });

    fs.mkdirSync(path.join(tempRoot, 'node_modules', 'fake-native'), { recursive: true });
    writeFixtureFile(path.join(tempRoot, 'node_modules', 'fake-native', 'binding.node'), '');
    blocked = releaseCheck.scanReleaseTree(tempRoot);
    assert(blocked.some(item => item.packagePath === 'node_modules/' && /dependencias nativas/.test(item.reason)), 'node_modules falso deve bloquear release sem depender de .gitignore');
    fs.rmSync(path.join(tempRoot, 'node_modules'), { recursive: true, force: true });

    writeFixtureFile(path.join(tempRoot, '.env'), 'SESSION_SECRET=segredo\n');
    blocked = releaseCheck.scanReleaseTree(tempRoot);
    assert(blocked.some(item => item.packagePath === '.env' && /segredos/.test(item.reason)), '.env falso deve bloquear release');
    fs.rmSync(path.join(tempRoot, '.env'), { force: true });

    writeFixtureFile(path.join(tempRoot, 'backup-database-old.db'), '');
    blocked = releaseCheck.scanReleaseTree(tempRoot);
    assert(blocked.some(item => item.packagePath === 'backup-database-old.db'), 'arquivo com nome de backup/banco antigo deve bloquear release');
    assert(releaseCheck.formatBlockedArtifacts(blocked).includes('Sugestao:'), 'mensagem de erro deve trazer sugestao curta');
    fs.rmSync(path.join(tempRoot, 'backup-database-old.db'), { force: true });

    assert.deepStrictEqual(releaseCheck.scanReleaseTree(tempRoot), [], 'pacote limpo deve voltar a passar depois de remover artefatos proibidos');
  } finally {
    fs.rmSync(tempRoot, { recursive: true, force: true });
  }
}

function assertSyntax(relDir) {
  const dir = path.join(ROOT, relDir);
  for (const entry of fs.readdirSync(dir)) {
    if (!entry.endsWith('.js')) continue;
    const relPath = path.join(relDir, entry);
    new vm.Script(read(relPath), { filename: relPath });
  }
}

